1	import type * as DMMF from '@prisma/dmmf'
2	import { hasOwnProperty } from '@prisma/internals'
3	import * as ts from '@prisma/ts-builders'
4	
5	import type { DMMFHelper } from '../dmmf'
6	import { getPayloadName } from '../utils'
7	import { GraphQLScalarToJSTypeTable } from '../utils/common'
8	
9	export function buildModelOutputProperty(field: DMMF.Field, dmmf: DMMFHelper) {
10	  let fieldTypeName = hasOwnProperty(GraphQLScalarToJSTypeTable, field.type)
11	    ? GraphQLScalarToJSTypeTable[field.type]
12	    : field.type
13	  if (Array.isArray(fieldTypeName)) {
14	    fieldTypeName = fieldTypeName[0]
15	  }
16	
17	  let fieldType: ts.TypeBuilder
18	  if (field.kind === 'object') {
19	    const payloadType = ts.namedType(getPayloadName(field.type))
20	    if (!dmmf.isComposite(field.type)) {
21	      payloadType.addGenericArgument(ts.namedType('ExtArgs'))
22	    }
23	    fieldType = payloadType
24	  } else if (field.kind === 'enum') {
25	    fieldType = ts.namedType(`$Enums.${fieldTypeName}`)
26	  } else {
27	    fieldType = ts.namedType(fieldTypeName)
28	  }
29	
30	  if (field.isList) {
31	    fieldType = ts.array(fieldType)
32	  } else if (!field.isRequired) {
33	    fieldType = ts.unionType(fieldType).addVariant(ts.nullType)
34	  }
35	  const property = ts.property(field.name, fieldType)
36	  if (field.documentation) {
37	    property.setDocComment(ts.docComment(field.documentation))
38	  }
39	  return property
40	}
41	
42	export function buildOutputType(type: DMMF.OutputType) {
43	  return ts.moduleExport(ts.typeDeclaration(type.name, ts.objectType().addMultiple(type.fields.map(buildOutputField))))
44	}
45	
46	function buildOutputField(field: DMMF.SchemaField) {
47	  let fieldType: ts.TypeBuilder
48	
49	  if (field.outputType.location === 'enumTypes' && field.outputType.namespace === 'model') {
50	    fieldType = ts.namedType(enumTypeName(field.outputType))
51	  } else {
52	    const typeNames = GraphQLScalarToJSTypeTable[field.outputType.type] ?? field.outputType.type
53	    fieldType = Array.isArray(typeNames) ? ts.namedType(typeNames[0]) : ts.namedType(typeNames)
54	  }
55	
56	  if (field.outputType.isList) {
57	    fieldType = ts.array(fieldType)
58	  } else if (field.isNullable) {
59	    fieldType = ts.unionType(fieldType).addVariant(ts.nullType)
60	  }
61	
62	  const property = ts.property(field.name, fieldType)
63	  if (field.deprecation) {
64	    property.setDocComment(
65	      ts.docComment(`@deprecated since ${field.deprecation.sinceVersion} because ${field.deprecation.reason}`),
66	    )
67	  }
68	
69	  return property
70	}
71	
72	function enumTypeName(ref: DMMF.OutputTypeRef) {
73	  const name = ref.type
74	  const namespace = ref.namespace === 'model' ? '$Enums' : 'Prisma'
75	  return `${namespace}.${name}`
76	}
