import type * as DMMF from '@prisma/dmmf'

import { prismaScalarToTs } from './scalar-types'

/**
 * Generates TypeScript source for `types.ts` — one interface per model plus
 * `Create<Model>Input` and `Update<Model>Input` helper types.
 */
export function generateTypes(models: DMMF.Model[], enums: DMMF.DatamodelEnum[]): string {
  const enumNames = new Set(enums.map((e) => e.name))

  // Collect enum names actually referenced by any field so we can build the import.
  const usedEnumNames = new Set<string>()
  for (const model of models) {
    for (const field of model.fields) {
      if (field.kind === 'enum') {
        usedEnumNames.add(field.type)
      }
    }
  }

  const lines: string[] = []

  if (usedEnumNames.size > 0) {
    lines.push(`import type { ${[...usedEnumNames].sort().join(', ')} } from './enums'`)
    lines.push('')
  }

  lines.push(...models.map((m) => renderModelTypes(m, enumNames)).join('\n\n').split('\n'))

  return lines.join('\n') + '\n'
}

// ---------------------------------------------------------------------------
// Internal helpers
// ---------------------------------------------------------------------------

/** Returns the TypeScript type string for a single field in the model interface. */
function fieldToInterfaceType(field: DMMF.Field): string {
  let type: string
  if (field.kind === 'enum') {
    type = field.type
  } else if (field.kind === 'object') {
    type = field.type
  } else {
    type = prismaScalarToTs(field.type)
  }
  if (field.isList) {
    type = `${type}[]`
  } else if (!field.isRequired) {
    type = `${type} | null`
  }
  return type
}

/** Returns the TypeScript type string for a field inside an input type (never nullable union). */
function fieldToInputType(field: DMMF.Field): string {
  let type: string
  if (field.kind === 'enum') {
    type = field.type
  } else {
    type = prismaScalarToTs(field.type)
  }
  if (field.isList) {
    type = `${type}[]`
  } else if (!field.isRequired) {
    type = `${type} | null`
  }
  return type
}

/**
 * Returns true for fields that should be excluded from create/update inputs:
 * auto-generated IDs, `@updatedAt` fields, and other generated fields.
 */
function isInputExcluded(field: DMMF.Field): boolean {
  if (field.kind === 'object') return true
  if (field.isGenerated) return true
  if (field.isUpdatedAt) return true
  // Auto-generated ID (e.g. autoincrement, cuid, uuid)
  if (field.isId && field.hasDefaultValue) return true
  return false
}

function renderModelTypes(model: DMMF.Model, _enumNames: Set<string>): string {
  // --- Model interface ---
  const interfaceFields = model.fields
    .map((f) => {
      const optional = f.kind === 'object' && !f.isRequired ? '?' : !f.isRequired ? '' : ''
      // Relation fields are optional on the interface (may not be included in response)
      const isRelation = f.kind === 'object'
      const opt = isRelation ? '?' : ''
      return `  ${f.name}${opt}: ${fieldToInterfaceType(f)}`
    })
    .join('\n')

  // --- CreateInput ---
  const createFields = model.fields
    .filter((f) => !isInputExcluded(f))
    .map((f) => {
      const isOptional = !f.isRequired || f.hasDefaultValue
      const opt = isOptional ? '?' : ''
      return `  ${f.name}${opt}: ${fieldToInputType(f)}`
    })
    .join('\n')

  // --- UpdateInput (all fields optional) ---
  const updateFields = model.fields
    .filter((f) => !isInputExcluded(f))
    .map((f) => `  ${f.name}?: ${fieldToInputType(f)}`)
    .join('\n')

  return [
    `export interface ${model.name} {`,
    interfaceFields,
    `}`,
    ``,
    `export interface Create${model.name}Input {`,
    createFields,
    `}`,
    ``,
    `export interface Update${model.name}Input {`,
    updateFields,
    `}`,
  ].join('\n')
}

