import type * as DMMF from '@prisma/dmmf'

import { prismaScalarToTs } from './scalar-types'

/**
 * Generates TypeScript source for `client.ts` — a `RestApiClient` class whose
 * constructor takes `baseUrl: string`.  Each model gets a namespaced property
 * (camelCase plural) with five CRUD methods backed by `fetch`.
 */
export function generateCrudClient(models: DMMF.Model[], modelOperations: DMMF.ModelMapping[]): string {
  const pluralMap = new Map(modelOperations.map((op) => [op.model, op.plural]))

  const importedTypes = models.flatMap((m) => [m.name, `Create${m.name}Input`, `Update${m.name}Input`])

  const lines: string[] = [
    `import type { ${importedTypes.join(', ')} } from './types'`,
    '',
    `export class RestApiClient {`,
    `  readonly #baseUrl: string`,
    '',
    `  constructor(baseUrl: string) {`,
    `    this.#baseUrl = baseUrl.replace(/\\/$/, '')`,
    `  }`,
    '',
  ]

  for (const model of models) {
    const plural = (pluralMap.get(model.name) ?? `${model.name}s`).toLowerCase()
    lines.push(...renderModelNamespace(model, plural))
  }

  lines.push(`}`)
  lines.push('')

  return lines.join('\n')
}

// ---------------------------------------------------------------------------
// Internal helpers
// ---------------------------------------------------------------------------

function getIdType(model: DMMF.Model): string {
  const idField = model.fields.find((f) => f.isId)
  if (!idField || idField.kind !== 'scalar') {
    // Composite ID or no ID — fall back to string
    return 'string'
  }
  return prismaScalarToTs(idField.type)
}

/** Converts `"User"` → `"user"`, `"BlogPost"` → `"blogPost"`. */
function toCamelCase(name: string): string {
  return name.charAt(0).toLowerCase() + name.slice(1)
}

function renderModelNamespace(model: DMMF.Model, urlSegment: string): string[] {
  const prop = toCamelCase(model.name)
  const idType = getIdType(model)

  return [
    `  readonly ${prop} = {`,
    `    findMany: (params?: { skip?: number; take?: number }): Promise<${model.name}[]> => {`,
    `      const url = new URL(\`\${this.#baseUrl}/${urlSegment}\`)`,
    `      if (params?.skip !== undefined) url.searchParams.set('skip', String(params.skip))`,
    `      if (params?.take !== undefined) url.searchParams.set('take', String(params.take))`,
    `      return fetch(url.toString()).then((r) => r.json() as Promise<${model.name}[]>)`,
    `    },`,
    `    findUnique: (id: ${idType}): Promise<${model.name} | null> => {`,
    `      return fetch(\`\${this.#baseUrl}/${urlSegment}/\${id}\`).then((r) =>`,
    `        r.ok ? (r.json() as Promise<${model.name}>) : null`,
    `      )`,
    `    },`,
    `    create: (data: Create${model.name}Input): Promise<${model.name}> => {`,
    `      return fetch(\`\${this.#baseUrl}/${urlSegment}\`, {`,
    `        method: 'POST',`,
    `        headers: { 'Content-Type': 'application/json' },`,
    `        body: JSON.stringify(data),`,
    `      }).then((r) => r.json() as Promise<${model.name}>)`,
    `    },`,
    `    update: (id: ${idType}, data: Update${model.name}Input): Promise<${model.name}> => {`,
    `      return fetch(\`\${this.#baseUrl}/${urlSegment}/\${id}\`, {`,
    `        method: 'PATCH',`,
    `        headers: { 'Content-Type': 'application/json' },`,
    `        body: JSON.stringify(data),`,
    `      }).then((r) => r.json() as Promise<${model.name}>)`,
    `    },`,
    `    delete: (id: ${idType}): Promise<${model.name}> => {`,
    `      return fetch(\`\${this.#baseUrl}/${urlSegment}/\${id}\`, { method: 'DELETE' }).then((r) =>`,
    `        r.json() as Promise<${model.name}>`,
    `      )`,
    `    },`,
    `  }`,
    '',
  ]
}

