import { generateCrudClient } from '../generate-crud-client'
import { generateEnums } from '../generate-enums'
import { generateTypes } from '../generate-types'

// ---------------------------------------------------------------------------
// Shared fixtures
// ---------------------------------------------------------------------------

const statusEnum: DMMF.DatamodelEnum = {
  name: 'Status',
  values: [
    { name: 'ACTIVE', dbName: null },
    { name: 'INACTIVE', dbName: null },
  ],
  dbName: null,
}

/** A User model with typical auto-increment ID, unique email, nullable name,
 *  auto-set timestamps, an enum field, and a relation to Post. */
const userModel: DMMF.Model = {
  name: 'User',
  dbName: null,
  schema: null,
  fields: [
    {
      kind: 'scalar',
      name: 'id',
      isRequired: true,
      isList: false,
      isUnique: false,
      isId: true,
      isReadOnly: false,
      hasDefaultValue: true,
      type: 'Int',
      default: { name: 'autoincrement', args: [] },
    },
    {
      kind: 'scalar',
      name: 'email',
      isRequired: true,
      isList: false,
      isUnique: true,
      isId: false,
      isReadOnly: false,
      hasDefaultValue: false,
      type: 'String',
    },
    {
      kind: 'scalar',
      name: 'name',
      isRequired: false,
      isList: false,
      isUnique: false,
      isId: false,
      isReadOnly: false,
      hasDefaultValue: false,
      type: 'String',
    },
    {
      kind: 'scalar',
      name: 'createdAt',
      isRequired: true,
      isList: false,
      isUnique: false,
      isId: false,
      isReadOnly: false,
      isUpdatedAt: false,
      hasDefaultValue: true,
      type: 'DateTime',
      default: { name: 'now', args: [] },
    },
    {
      kind: 'scalar',
      name: 'updatedAt',
      isRequired: true,
      isList: false,
      isUnique: false,
      isId: false,
      isReadOnly: false,
      isUpdatedAt: true,
      hasDefaultValue: false,
      type: 'DateTime',
    },
    {
      kind: 'enum',
      name: 'status',
      isRequired: true,
      isList: false,
      isUnique: false,
      isId: false,
      isReadOnly: false,
      hasDefaultValue: false,
      type: 'Status',
    },
    {
      kind: 'object',
      name: 'posts',
      isRequired: false,
      isList: true,
      isUnique: false,
      isId: false,
      isReadOnly: false,
      hasDefaultValue: false,
      type: 'Post',
      relationName: 'UserPosts',
      relationFromFields: [],
      relationToFields: [],
    },
  ],
  uniqueFields: [],
  uniqueIndexes: [],
  primaryKey: null,
}

const userModelOperations: DMMF.ModelMapping = {
  model: 'User',
  plural: 'users',
  findUnique: 'findUniqueUser',
  findFirst: 'findFirstUser',
  findMany: 'findManyUser',
  create: 'createOneUser',
  update: 'updateOneUser',
  delete: 'deleteOneUser',
}

// ---------------------------------------------------------------------------
// generateEnums
// ---------------------------------------------------------------------------

describe('generateEnums', () => {
  test('returns empty string when there are no enums', () => {
    expect(generateEnums([])).toBe('')
  })

  test('generates a const object and companion type for each enum', () => {
    const output = generateEnums([statusEnum])
    expect(output).toContain("export const Status = {")
    expect(output).toContain("  ACTIVE: 'ACTIVE',")
    expect(output).toContain("  INACTIVE: 'INACTIVE',")
    expect(output).toContain('} as const')
    expect(output).toContain('export type Status = (typeof Status)[keyof typeof Status]')
  })
})

// ---------------------------------------------------------------------------
// generateTypes
// ---------------------------------------------------------------------------

describe('generateTypes', () => {
  test('generates the model interface with all fields', () => {
    const output = generateTypes([userModel], [statusEnum])
    // Scalar fields
    expect(output).toContain('id: number')
    expect(output).toContain('email: string')
    expect(output).toContain('name: string | null')
    expect(output).toContain('createdAt: string') // DateTime → string
    // Enum field
    expect(output).toContain('status: Status')
    // Relation field present as optional
    expect(output).toContain('posts?:')
  })

  test('generates an enum import when models reference enums', () => {
    const output = generateTypes([userModel], [statusEnum])
    expect(output).toContain("import type { Status } from './enums'")
  })

  test('CreateInput omits auto-ID, @updatedAt, and fields with auto defaults', () => {
    const output = generateTypes([userModel], [statusEnum])
    // id is @id @default(autoincrement) — must be omitted
    expect(output).not.toMatch(/Create\w+Input \{[^}]*\bid:/)
    // updatedAt is @updatedAt — must be omitted
    expect(output).not.toMatch(/Create\w+Input \{[^}]*\bupdatedAt:/)
    // relation posts — must be omitted
    expect(output).not.toMatch(/Create\w+Input \{[^}]*\bposts/)
    // required email must be present and required
    expect(output).toContain('email: string')
    // createdAt has @default(now()) — must be optional
    expect(output).toContain('createdAt?: string')
  })

  test('UpdateInput makes all mutable fields optional', () => {
    const output = generateTypes([userModel], [statusEnum])
    // In the UpdateInput block all fields should be optional (using ?)
    expect(output).toContain('email?: string')
    expect(output).toContain('status?: Status')
  })
})

// ---------------------------------------------------------------------------
// generateCrudClient
// ---------------------------------------------------------------------------

describe('generateCrudClient', () => {
  test('generates the RestApiClient class', () => {
    const output = generateCrudClient([userModel], [userModelOperations])
    expect(output).toContain('export class RestApiClient')
    expect(output).toContain('readonly #baseUrl: string')
    expect(output).toContain('constructor(baseUrl: string)')
  })

  test('generates a namespaced property for each model using plural lower-case URL segment', () => {
    const output = generateCrudClient([userModel], [userModelOperations])
    // Property name is camelCase of model name
    expect(output).toContain('readonly user =')
    // URL segment is lower-case plural from modelOperations
    expect(output).toContain('`${this.#baseUrl}/users`')
    expect(output).toContain('`${this.#baseUrl}/users/${id}`')
  })

  test('generates all five CRUD methods with correct return types', () => {
    const output = generateCrudClient([userModel], [userModelOperations])
    expect(output).toContain('findMany:')
    expect(output).toContain(`Promise<User[]>`)
    expect(output).toContain('findUnique:')
    expect(output).toContain(`Promise<User | null>`)
    expect(output).toContain('create:')
    expect(output).toContain(`Create${userModel.name}Input`)
    expect(output).toContain('update:')
    expect(output).toContain(`Update${userModel.name}Input`)
    expect(output).toContain('delete:')
  })

  test('uses the correct id type from the model @id field', () => {
    const output = generateCrudClient([userModel], [userModelOperations])
    // User.id is Int → number
    expect(output).toContain('findUnique: (id: number)')
    expect(output).toContain('update: (id: number,')
    expect(output).toContain('delete: (id: number)')
  })

  test('uses HTTP methods POST for create, PATCH for update, DELETE for delete', () => {
    const output = generateCrudClient([userModel], [userModelOperations])
    expect(output).toContain("method: 'POST'")
    expect(output).toContain("method: 'PATCH'")
    expect(output).toContain("method: 'DELETE'")
  })

  test('includes the type import from ./types', () => {
    const output = generateCrudClient([userModel], [userModelOperations])
    expect(output).toContain("import type {")
    expect(output).toContain("} from './types'")
    expect(output).toContain('User')
    expect(output).toContain('CreateUserInput')
    expect(output).toContain('UpdateUserInput')
  })
})

